/**
 * Initializes the Firebase Admin SDK if it hasn't been already.
 * This function is safe to call multiple times.
 */
export function initializeAdminApp(): App {
  const appName = 'firebase-admin-app-[StakIt Hire]';

  // Check if the app with the specific name already exists.
  const existingApp = getApps().find(app => app.name === appName);
  if (existingApp) {
    return existingApp;
  }

  if (!serviceAccountKey.project_id || !serviceAccountKey.private_key || !serviceAccountKey.client_email) {
    throw new Error('Firebase Admin SDK credentials are not set. Cannot initialize.');
  }

  // Initialize a new app with a unique name.
  return initializeApp({
    credential: cert(serviceAccountKey),
  }, appName);
}
